import{_ as e,o as t,c as n,a3 as a}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"16. Anti Discrimination","description":"","frontmatter":{"title":"16. Anti Discrimination","eba":"Mental Health Services 2024-2028","topics":["leave","family-violence-leave","flexible-work","preliminary","discrimination"]},"headers":[],"relativePath":"ebas/mental-health/common-terms/preliminary/16-anti-discrimination.md","filePath":"ebas/mental-health/common-terms/preliminary/16-anti-discrimination.md"}'),r={name:"ebas/mental-health/common-terms/preliminary/16-anti-discrimination.md"};function o(s,i,c,l,m,p){return t(),n("div",null,[...i[0]||(i[0]=[a('<h1 id="_16-anti-discrimination" tabindex="-1">16. Anti Discrimination <a class="header-anchor" href="#_16-anti-discrimination" aria-label="Permalink to &quot;16. Anti Discrimination&quot;">​</a></h1><p><strong>16.1</strong> It is the intention of the parties covered by this Agreement to achieve the principal object in section 3(e) of the Act through respecting and valuing the diversity of the workforce by helping to prevent and eliminate discrimination on the basis of race, colour, sex, sexual orientation , breastfeeding, gender identity, intersex status, and experience of family and domestic violence, age, physical or mental disability, marital status, family or carer responsibilities, pregnancy, religion, political opinion, national extraction or social origin.</p><p><strong>16.2</strong> The Parties must make every endeavour to ensure that neither the Agreement provisions nor their operation are directly or indirectly discriminatory in their effects.</p><p><strong>16.3</strong> Nothing in this clause is to be taken to affect:</p><p><strong>(a)</strong> any different treatment (or treatment having different effects) which is specifically exempted under the Commonwealth anti-discrimination legislation; or</p><p><strong>(b)</strong> an Employee, Employer or registered organisation pursuing matters of discrimination in any State or Federal jurisdiction, including by application to the Australian Human Rights Commission; or</p><p><strong>(c)</strong> any exemptions provided under the Act.</p><p>Plain language terms: discrimination, equal opportunity, race, disability.</p>',8)])])}const g=e(r,[["render",o]]);export{h as __pageData,g as default};
